console.log("Comparing null and undefined:");
console.log("Loose null == undefined:", null == undefined);
console.log("Strict null === undefined:", null === undefined);

codeExample2.code:
const fetchUserData = () => {
  return {
    name: "Devin",
    settings: {
      theme: "dark",
      volume: 0 // A falsy number we want to keep!
    }
  };
};

const user = fetchUserData();

// Accessing nested settings safely
const zipCode = user.location?.zipCode ?? "00000";
console.log("Zip Code:", zipCode);

// Comparing || and ?? with falsy values
const volumeWithOR = user.settings.volume || 100;
const volumeWithCoalescing = user.settings.volume ?? 100;

console.log("Volume using ||:", volumeWithOR);
console.log("Volume using ??:", volumeWithCoalescing);

